import time

class TTLCache:
    """Кэш с временем жизни записей (TTL в секундах)."""

    def __init__(self, ttl: int):
        self.ttl = ttl
        self.store = {}   # key -> (value, timestamp)

    def set(self, key: str, value) -> None:
        self.store[key] = (value, time.time())

    def get(self, key: str):
        if key not in self.store:
            return None
        value, ts = self.store[key]
        # BUG: сравниваем не разницу времён, а сам timestamp с ttl
        if ts < self.ttl:
            del self.store[key]
            return None
        return value
